56	// NewPreClaimIntakeHook constructs the bead-intake complexity gate used
57	// before claim in the work / execute-loop paths. The hook evaluates the bead
58	// using the repository's triage prompt and returns one of the typed intake
59	// outcomes so the loop can decide whether to claim or skip the candidate.
60	//
61	// The hook preserves operator-supplied passthrough constraints. When the
62	// resolved route cannot satisfy the strong splitter floor, it returns an
63	// actionable-but-blocking result with agent_power_unsatisfied in the detail so
64	// the loop can skip the bead instead of attempting weak decomposition.
65	func NewPreClaimIntakeHook(projectRoot string, store BeadReader, rcfg config.ResolvedConfig, svc agentlib.FizeauService, runner AgentRunner) func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
66		return func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
67			if ctx != nil {
68				if err := ctx.Err(); err != nil {
69					return PreClaimIntakeResult{}, err
70				}
71			}
72			if strings.TrimSpace(projectRoot) == "" {
73				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: project root required")
74			}
75			if err := ensureBeadLifecycleSkill(projectRoot); err != nil {
76				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: %w", err)
77			}
78			if store == nil {
79				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: bead reader required")
80			}
81	
82			b, err := store.Get(beadID)
83			if err != nil {
84				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: load bead %s: %w", beadID, err)
85			}
86	
87			prompt, err := buildPreClaimIntakePrompt(projectRoot, store, b)
88			if err != nil {
89				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: build prompt: %w", err)
90			}
91	
92			strongMinPower := resolveStrongSplitterMinPower(ctx, projectRoot, svc)
93			if rcfg.MinPower() > strongMinPower {
94				strongMinPower = rcfg.MinPower()
95			}
96	
97			runtime := AgentRunRuntime{
98				Prompt:          prompt,
99				WorkDir:         projectRoot,
100				PromptSource:    PreClaimIntakePromptSource,
101				ProfileOverride: "smart",
102				ClearMaxPower:   true,
103			}
104			if strongMinPower > 0 {
105				runtime.MinPowerOverride = strongMinPower
106			}
107			payload, err := dispatchPreClaimIntakePayload(ctx, projectRoot, svc, runner, rcfg, runtime, strongMinPower)
108			if err != nil {
109				if isStrongPowerUnsatisfiedError(err) {
110					return PreClaimIntakeResult{
111						Outcome: PreClaimIntakeAmbiguousNeedsHuman,
112						Detail:  "pre-claim intake requires a smart/frontier route but no viable model was available",
113					}, nil
114				}
115				return PreClaimIntakeResult{}, err
116			}
117	
118			return decodePreClaimIntakePayloadResult(payload)
119		}
120	}
121	
122	func dispatchPreClaimIntakePayload(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, rcfg config.ResolvedConfig, runtime AgentRunRuntime, strongMinPower int) (string, error) {
123		payload, err := dispatchPreClaimIntakePayloadOnce(ctx, projectRoot, svc, runner, rcfg, runtime)
124		if err == nil {
125			return payload, nil
126		}
127		if runtime.ProfileOverride != "smart" || strongMinPower > 0 || !isSmartProfileUnavailableError(err) {
128			return "", err
129		}
130	
131		runtime.ProfileOverride = DefaultRoutingProfile
132		return dispatchPreClaimIntakePayloadOnce(ctx, projectRoot, svc, runner, rcfg, runtime)
133	}
134	
135	func dispatchPreClaimIntakePayloadOnce(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (string, error) {
136		result, err := dispatchViaResolvedConfig(ctx, projectRoot, svc, runner, rcfg, runtime)
137		if err != nil {
138			return "", fmt.Errorf("pre-claim intake: dispatch: %w", err)
139		}
140		return intakeResultPayload(result)
141	}
