package agent

import (
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"regexp"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

type preClaimIntakeRewriteSnapshot struct {
	DescriptionBytes int    `json:"description_bytes,omitempty"`
	AcceptanceBytes  int    `json:"acceptance_bytes,omitempty"`
	DescriptionSHA   string `json:"description_sha256,omitempty"`
	AcceptanceSHA    string `json:"acceptance_sha256,omitempty"`
}

type preClaimIntakeRewriteEventBody struct {
	Rationale            string                        `json:"rationale,omitempty"`
	ChangedFields        []string                      `json:"changed_fields,omitempty"`
	Before               preClaimIntakeRewriteSnapshot `json:"before"`
	After                preClaimIntakeRewriteSnapshot `json:"after"`
	PreservationEvidence []string                      `json:"preservation_evidence,omitempty"`
}

// Patterns for extracting explicit commitments from bead descriptions.
// A commitment is a durable anchor that must survive a replacement rewrite.
var (
	reGoverningRef = regexp.MustCompile(`\b[A-Z]{2,6}-\d{3,}\b`)
	reNamedTest    = regexp.MustCompile(`\bTest[A-Z]\w+\b`)
	reFileLine     = regexp.MustCompile(`\b[\w/.-]+\.go:\d+\b`)
	reDepID        = regexp.MustCompile(`\bddx-[0-9a-f]{8}\b`)
)

var descriptionSectionHeaders = []string{
	"PROBLEM", "ROOT CAUSE", "PROPOSED FIX", "NON-SCOPE", "NON SCOPE",
	"CONTEXT", "PARENT", "DEPS", "DEPENDENCIES", "BACKGROUND",
}

func isDescriptionSectionHeader(line string) bool {
	upper := strings.ToUpper(strings.TrimRight(normalizeWhitespace(line), ":"))
	for _, h := range descriptionSectionHeaders {
		if upper == h {
			return true
		}
	}
	return false
}

// extractNonScopeBullets returns normalized bullet text from the NON-SCOPE
// section of a bead description.
func extractNonScopeBullets(desc string) []string {
	lines := strings.Split(desc, "\n")
	var inNonScope bool
	var result []string
	for _, line := range lines {
		trimmed := strings.TrimSpace(line)
		upper := strings.ToUpper(strings.TrimRight(normalizeWhitespace(trimmed), ":"))
		if upper == "NON-SCOPE" || upper == "NON SCOPE" {
			inNonScope = true
			continue
		}
		if inNonScope {
			if trimmed == "" {
				continue
			}
			if isDescriptionSectionHeader(trimmed) {
				inNonScope = false
				continue
			}
			bullet := strings.TrimLeft(trimmed, "-•*+# ")
			bullet = normalizeWhitespace(bullet)
			if bullet != "" {
				result = append(result, bullet)
			}
		}
	}
	return result
}

// extractDescriptionCommitments returns durable anchor strings that must be
// preserved across a description replacement rewrite:
//   - Governing artifact references (FEAT-010, ADR-023, etc.)
//   - Named test functions (TestFoo)
//   - File:line references (pkg/file.go:42)
//   - Dependency IDs (ddx-XXXXXXXX)
//   - NON-SCOPE section bullet points (prefixed with "non_scope:")
func extractDescriptionCommitments(desc string) []string {
	seen := make(map[string]struct{})
	var result []string
	add := func(s string) {
		if _, ok := seen[s]; !ok {
			seen[s] = struct{}{}
			result = append(result, s)
		}
	}
	for _, m := range reGoverningRef.FindAllString(desc, -1) {
		add(m)
	}
	for _, m := range reNamedTest.FindAllString(desc, -1) {
		add(m)
	}
	for _, m := range reFileLine.FindAllString(desc, -1) {
		add(m)
	}
	for _, m := range reDepID.FindAllString(desc, -1) {
		add(m)
	}
	for _, bullet := range extractNonScopeBullets(desc) {
		add("non_scope:" + bullet)
	}
	return result
}

// validateDescriptionReplacement checks that all explicit commitments in the
// old description are preserved in the new description. It returns the list of
// preservation evidence entries recorded. An error is returned if any
// commitment is missing from the replacement.
func validateDescriptionReplacement(oldDesc, newDesc string) ([]string, error) {
	commitments := extractDescriptionCommitments(oldDesc)
	normNew := normalizeWhitespace(newDesc)
	var evidence []string
	for _, c := range commitments {
		if strings.HasPrefix(c, "non_scope:") {
			checkIn := strings.TrimPrefix(c, "non_scope:")
			if !strings.Contains(normNew, checkIn) {
				return nil, fmt.Errorf("pre-claim intake rewrite: description drops commitment %q", c)
			}
		} else {
			if !strings.Contains(newDesc, c) {
				return nil, fmt.Errorf("pre-claim intake rewrite: description drops commitment %q", c)
			}
		}
		evidence = append(evidence, c)
	}
	return evidence, nil
}

func applyPreClaimIntakeRewrite(store ExecuteBeadLoopStore, beadID, actor string, intake PreClaimIntakeResult, createdAt time.Time) error {
	if store == nil {
		return fmt.Errorf("pre-claim intake rewrite: bead store required")
	}
	if strings.TrimSpace(beadID) == "" {
		return fmt.Errorf("pre-claim intake rewrite: bead id required")
	}
	if intake.normalizedOutcome() != PreClaimIntakeActionableButRewritten {
		return fmt.Errorf("pre-claim intake rewrite: unexpected outcome %q", intake.normalizedOutcome())
	}

	original, err := store.Get(beadID)
	if err != nil {
		return fmt.Errorf("pre-claim intake rewrite: load bead %s: %w", beadID, err)
	}

	rewrite, before, after, preservation, err := validateAndApplyPreClaimIntakeRewrite(original, intake.Rewrite)
	if err != nil {
		return err
	}

	if err := store.Update(beadID, func(b *bead.Bead) {
		if rewrite.Description != "" {
			b.Description = rewrite.Description
		}
		if rewrite.Acceptance != "" {
			b.Acceptance = rewrite.Acceptance
		}
	}); err != nil {
		return fmt.Errorf("pre-claim intake rewrite: update bead %s: %w", beadID, err)
	}

	body, err := json.Marshal(preClaimIntakeRewriteEventBody{
		Rationale:            strings.TrimSpace(intake.Detail),
		ChangedFields:        rewrite.ChangedFields,
		Before:               before,
		After:                after,
		PreservationEvidence: preservation,
	})
	if err != nil {
		return fmt.Errorf("pre-claim intake rewrite: encode event: %w", err)
	}

	summary := strings.Join(rewrite.ChangedFields, ",")
	if summary == "" {
		summary = "rewritten"
	}
	return store.AppendEvent(beadID, bead.BeadEvent{
		Kind:      "intake-rewritten",
		Summary:   summary,
		Body:      string(body),
		Actor:     actor,
		Source:    "ddx agent execute-loop",
		CreatedAt: createdAt.UTC(),
	})
}

func validateAndApplyPreClaimIntakeRewrite(original *bead.Bead, rewrite PreClaimIntakeRewrite) (PreClaimIntakeRewrite, preClaimIntakeRewriteSnapshot, preClaimIntakeRewriteSnapshot, []string, error) {
	errOut := func(msg string, args ...any) (PreClaimIntakeRewrite, preClaimIntakeRewriteSnapshot, preClaimIntakeRewriteSnapshot, []string, error) {
		return PreClaimIntakeRewrite{}, preClaimIntakeRewriteSnapshot{}, preClaimIntakeRewriteSnapshot{}, nil, fmt.Errorf(msg, args...)
	}

	if original == nil {
		return errOut("pre-claim intake rewrite: bead required")
	}

	normalized := PreClaimIntakeRewrite{
		Description:   strings.TrimSpace(rewrite.Description),
		Acceptance:    strings.TrimSpace(rewrite.Acceptance),
		ChangedFields: normalizePreClaimIntakeRewriteFields(rewrite.ChangedFields),
	}
	if len(normalized.ChangedFields) == 0 {
		return errOut("pre-claim intake rewrite: missing changed_fields")
	}

	allowed := map[string]struct{}{
		"description": {},
		"acceptance":  {},
	}
	for _, field := range normalized.ChangedFields {
		if _, ok := allowed[field]; !ok {
			return errOut("pre-claim intake rewrite: unsafe field %q", field)
		}
	}

	before := snapshotPreClaimIntakeRewrite(original.Description, original.Acceptance)

	var preservation []string
	oldDescription := strings.TrimSpace(original.Description)
	if hasString(normalized.ChangedFields, "description") {
		if normalized.Description == "" {
			return errOut("pre-claim intake rewrite: description rewrite missing")
		}
		if strings.EqualFold(strings.TrimSpace(normalized.Description), oldDescription) {
			return errOut("pre-claim intake rewrite: description unchanged")
		}
		ev, err := validateDescriptionReplacement(oldDescription, normalized.Description)
		if err != nil {
			return PreClaimIntakeRewrite{}, preClaimIntakeRewriteSnapshot{}, preClaimIntakeRewriteSnapshot{}, nil, err
		}
		preservation = ev
	} else if normalized.Description != "" {
		return errOut("pre-claim intake rewrite: description supplied without changed_fields")
	}

	oldAcceptance := strings.TrimSpace(original.Acceptance)
	if hasString(normalized.ChangedFields, "acceptance") {
		if normalized.Acceptance == "" {
			return errOut("pre-claim intake rewrite: acceptance rewrite missing")
		}
		if strings.EqualFold(strings.TrimSpace(normalized.Acceptance), oldAcceptance) {
			return errOut("pre-claim intake rewrite: acceptance unchanged")
		}
		if !acceptancePreservesCriteria(oldAcceptance, normalized.Acceptance) {
			return errOut("pre-claim intake rewrite: acceptance criteria dropped or altered")
		}
	} else if normalized.Acceptance != "" {
		return errOut("pre-claim intake rewrite: acceptance supplied without changed_fields")
	}

	afterDescription := oldDescription
	if containsString(normalized.ChangedFields, "description") {
		afterDescription = normalized.Description
	}
	afterAcceptance := oldAcceptance
	if containsString(normalized.ChangedFields, "acceptance") {
		afterAcceptance = normalized.Acceptance
	}
	after := snapshotPreClaimIntakeRewrite(afterDescription, afterAcceptance)
	return normalized, before, after, preservation, nil
}

func snapshotPreClaimIntakeRewrite(description, acceptance string) preClaimIntakeRewriteSnapshot {
	return preClaimIntakeRewriteSnapshot{
		DescriptionBytes: len(description),
		AcceptanceBytes:  len(acceptance),
		DescriptionSHA:   hashText(description),
		AcceptanceSHA:    hashText(acceptance),
	}
}

func hashText(text string) string {
	sum := sha256.Sum256([]byte(text))
	return hex.EncodeToString(sum[:])
}

func acceptancePreservesCriteria(before, after string) bool {
	beforeCriteria := parseAcceptanceCriteria(before)
	afterCriteria := parseAcceptanceCriteria(after)
	if len(beforeCriteria) == 0 {
		beforeCriteria = []string{normalizeWhitespace(strings.TrimSpace(before))}
	}
	if len(afterCriteria) == 0 {
		afterCriteria = []string{normalizeWhitespace(strings.TrimSpace(after))}
	}
	if len(afterCriteria) < len(beforeCriteria) {
		return false
	}
	for _, criterion := range beforeCriteria {
		found := false
		for _, candidate := range afterCriteria {
			if strings.Contains(candidate, criterion) {
				found = true
				break
			}
		}
		if !found {
			return false
		}
	}
	return true
}

func parseAcceptanceCriteria(raw string) []string {
	lines := strings.Split(raw, "\n")
	out := make([]string, 0, len(lines))
	for _, line := range lines {
		if body, ok := parseAcceptanceCriterionBody(line); ok {
			out = append(out, body)
		}
	}
	return out
}

func parseAcceptanceCriterionBody(line string) (string, bool) {
	trimmed := strings.TrimSpace(line)
	if trimmed == "" {
		return "", false
	}
	dot := strings.Index(trimmed, ".")
	if dot <= 0 {
		return "", false
	}
	if !allDigits(trimmed[:dot]) {
		return "", false
	}
	body := normalizeWhitespace(strings.TrimSpace(trimmed[dot+1:]))
	if body == "" {
		return "", false
	}
	return body, true
}

func allDigits(s string) bool {
	if s == "" {
		return false
	}
	for _, r := range s {
		if r < '0' || r > '9' {
			return false
		}
	}
	return true
}

func normalizeWhitespace(s string) string {
	return strings.Join(strings.Fields(strings.TrimSpace(s)), " ")
}

func hasString(values []string, target string) bool {
	for _, v := range values {
		if v == target {
			return true
		}
	}
	return false
}

package agent

import (
	"encoding/json"
	"path/filepath"
	"strings"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestPreClaimIntakeRewrite_AllowsCompressionReplacement verifies that a
// replacement description can remove stale/noisy old prose when explicit
// commitments and durable anchors are preserved. (AC1)
func TestPreClaimIntakeRewrite_AllowsCompressionReplacement(t *testing.T) {
	original := &bead.Bead{
		ID: "ddx-test0001",
		Description: "PROBLEM\nThe old intake system duplicated stale chat noise in every bead prompt." +
			" Extra: references to slack thread 2025-01, per internal RFC-47.\n\n" +
			"ROOT CAUSE\ncli/internal/agent/preclaim_intake_rewrite.go:119 enforces append-only check\n\n" +
			"PROPOSED FIX\nReplace substring check per FEAT-010 and ADR-023\n\n" +
			"NON-SCOPE\nDo not change acceptance criteria validator\n",
		Acceptance: "1. TestPreClaimIntakeRewrite_AllowsCompressionReplacement\n2. cd cli && go test ./internal/agent/... green\n",
	}
	// Compressed replacement: drops noisy prose, keeps all explicit commitments.
	compressedDesc := "PROBLEM\nAppend-only check rejects valid replacements per FEAT-010 and ADR-023.\n\n" +
		"ROOT CAUSE\ncli/internal/agent/preclaim_intake_rewrite.go:119 enforces substring containment\n\n" +
		"PROPOSED FIX\nReplace with commitment-based validation\n\n" +
		"NON-SCOPE\nDo not change acceptance criteria validator\n"

	rewrite := PreClaimIntakeRewrite{
		Description:   compressedDesc,
		ChangedFields: []string{"description"},
	}

	got, _, _, preservation, err := validateAndApplyPreClaimIntakeRewrite(original, rewrite)
	require.NoError(t, err)
	assert.Equal(t, compressedDesc, got.Description)
	assert.Contains(t, preservation, "FEAT-010")
	assert.Contains(t, preservation, "ADR-023")
	assert.Contains(t, preservation, "cli/internal/agent/preclaim_intake_rewrite.go:119")
	assert.Contains(t, preservation, "non_scope:Do not change acceptance criteria validator")
	// Stale prose is gone from the replacement.
	assert.NotContains(t, got.Description, "slack thread 2025-01")
	assert.NotContains(t, got.Description, "RFC-47")
}

// TestPreClaimIntakeRewrite_AllowsExpansionReplacement verifies that a vague
// one-line description can expand into a standalone executable bead when the
// added content is grounded in durable context and does not invent product
// semantics. (AC2)
func TestPreClaimIntakeRewrite_AllowsExpansionReplacement(t *testing.T) {
	original := &bead.Bead{
		ID:          "ddx-test0002",
		Description: "add a pre-claim rewrite hook",
		Acceptance:  "1. TestPreClaimIntakeRewrite_AllowsExpansionReplacement\n2. cd cli && go test ./internal/agent/... green\n",
	}
	// Expanded replacement: adds PROBLEM/ROOT CAUSE/PROPOSED FIX structure with
	// durable file:line anchors. Does not add any Test* functions or acceptance
	// criteria — those belong in the acceptance field.
	expandedDesc := "PROBLEM\nThe execute-loop dispatches beads without evaluating whether the " +
		"description is a fit-for-purpose implementation prompt.\n\n" +
		"ROOT CAUSE\ncli/internal/agent/execute_bead_loop.go:600 dispatches without readiness gate\n\n" +
		"PROPOSED FIX\nAdd PreClaimIntakeHook wired in the loop at claim time\n\n" +
		"NON-SCOPE\nDo not add acceptance criteria in this description\n"

	rewrite := PreClaimIntakeRewrite{
		Description:   expandedDesc,
		ChangedFields: []string{"description"},
	}

	got, _, _, preservation, err := validateAndApplyPreClaimIntakeRewrite(original, rewrite)
	require.NoError(t, err)
	assert.Equal(t, expandedDesc, got.Description)
	// No commitments in the vague one-liner, so preservation evidence is empty.
	assert.Empty(t, preservation)
	// Expansion adds durable context.
	assert.Contains(t, got.Description, "execute_bead_loop.go:600")
}

// TestPreClaimIntakeRewrite_RejectsDeletedCommitment verifies that non-scope
// items, governing artifact references, named tests, or unresolved constraints
// cannot be silently removed by a replacement rewrite. (AC3)
func TestPreClaimIntakeRewrite_RejectsDeletedCommitment(t *testing.T) {
	tests := []struct {
		name    string
		oldDesc string
		newDesc string
		wantErr string
	}{
		{
			name: "governing_ref_dropped",
			oldDesc: "PROBLEM\nfix intake per FEAT-010 and ADR-023\n\n" +
				"ROOT CAUSE\ncli/internal/agent/foo.go:10\n",
			newDesc:  "PROBLEM\nfix intake\n\nROOT CAUSE\ncli/internal/agent/foo.go:10\n",
			wantErr:  `drops commitment "FEAT-010"`,
		},
		{
			name: "non_scope_bullet_dropped",
			oldDesc: "PROBLEM\nfix intake\n\n" +
				"NON-SCOPE\nDo not rename existing structs\n",
			newDesc: "PROBLEM\nfix intake\n",
			wantErr: `drops commitment "non_scope:Do not rename existing structs"`,
		},
		{
			name: "named_test_dropped",
			oldDesc: "PROBLEM\nfix intake\n\n" +
				"ROOT CAUSE\nmust satisfy TestPreClaimIntakeHook\n",
			newDesc: "PROBLEM\nfix intake\n\nROOT CAUSE\nsee failing check\n",
			wantErr: `drops commitment "TestPreClaimIntakeHook"`,
		},
		{
			name: "file_line_dropped",
			oldDesc: "PROBLEM\nfix intake\n\n" +
				"ROOT CAUSE\ncli/internal/agent/preclaim_intake_rewrite.go:119\n",
			newDesc: "PROBLEM\nfix intake\n\nROOT CAUSE\nsome other cause\n",
			wantErr: `drops commitment "cli/internal/agent/preclaim_intake_rewrite.go:119"`,
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			original := &bead.Bead{
				ID:          "ddx-test0003",
				Description: tt.oldDesc,
				Acceptance:  "1. TestPreClaimIntakeRewrite_RejectsDeletedCommitment\n",
			}
			rewrite := PreClaimIntakeRewrite{
				Description:   tt.newDesc,
				ChangedFields: []string{"description"},
			}
			_, _, _, _, err := validateAndApplyPreClaimIntakeRewrite(original, rewrite)
			require.Error(t, err)
			assert.Contains(t, err.Error(), tt.wantErr)
		})
	}
}

// TestPreClaimIntakeRewrite_RecordsReplacementEvidence verifies that the
// intake-rewritten event records changed_fields, rationale, before/after
// hashes, and preservation_evidence sufficient to audit the original text
// without duplicating it in the replacement body. (AC4)
func TestPreClaimIntakeRewrite_RecordsReplacementEvidence(t *testing.T) {
	root := t.TempDir()
	store := bead.NewStore(filepath.Join(root, ".ddx"))
	require.NoError(t, store.Init())

	oldDesc := "PROBLEM\nstale chat noise from RFC-47\n\n" +
		"ROOT CAUSE\ncli/internal/agent/preclaim_intake_rewrite.go:119 enforces append-only\n\n" +
		"PROPOSED FIX\nReplace per FEAT-010\n\n" +
		"NON-SCOPE\nDo not change acceptance criteria validator\n"
	newDesc := "PROBLEM\nAppend-only check rejects valid replacements per FEAT-010.\n\n" +
		"ROOT CAUSE\ncli/internal/agent/preclaim_intake_rewrite.go:119 enforces substring containment\n\n" +
		"NON-SCOPE\nDo not change acceptance criteria validator\n"

	b := &bead.Bead{
		ID:          "ddx-test0004",
		Title:       "test: replacement evidence",
		IssueType:   bead.DefaultType,
		Status:      bead.StatusOpen,
		Priority:    1,
		Description: oldDesc,
		Acceptance:  "1. TestPreClaimIntakeRewrite_RecordsReplacementEvidence\n",
	}
	require.NoError(t, store.Create(b))

	intake := PreClaimIntakeResult{
		Outcome: PreClaimIntakeActionableButRewritten,
		Detail:  "compressed stale RFC-47 prose",
		Rewrite: PreClaimIntakeRewrite{
			Description:   newDesc,
			ChangedFields: []string{"description"},
		},
	}
	at := time.Date(2026, 5, 8, 0, 0, 0, 0, time.UTC)
	err := applyPreClaimIntakeRewrite(store, b.ID, "test-worker", intake, at)
	require.NoError(t, err)

	events, err := store.Events(b.ID)
	require.NoError(t, err)

	var found bool
	for _, ev := range events {
		if ev.Kind != "intake-rewritten" {
			continue
		}
		found = true
		var body preClaimIntakeRewriteEventBody
		require.NoError(t, json.Unmarshal([]byte(ev.Body), &body))

		// Rationale and changed fields are recorded.
		assert.Equal(t, "compressed stale RFC-47 prose", body.Rationale)
		assert.Equal(t, []string{"description"}, body.ChangedFields)

		// Before/after hashes are present and different.
		assert.NotEmpty(t, body.Before.DescriptionSHA)
		assert.NotEmpty(t, body.After.DescriptionSHA)
		assert.NotEqual(t, body.Before.DescriptionSHA, body.After.DescriptionSHA)

		// Preservation evidence lists the durable anchors that were checked.
		assert.Contains(t, body.PreservationEvidence, "FEAT-010")
		assert.Contains(t, body.PreservationEvidence, "cli/internal/agent/preclaim_intake_rewrite.go:119")
		assert.Contains(t, body.PreservationEvidence, "non_scope:Do not change acceptance criteria validator")

		// Original body is NOT duplicated in the event.
		assert.NotContains(t, ev.Body, "stale chat noise from RFC-47")
	}
	require.True(t, found, "intake-rewritten event must be recorded")
}

// TestPreClaimIntakePrompt_AsksForFitForPurposeValidatedReplacement verifies
// that the intake prompt tells the model to optimize prompt fitness, avoid
// append-only noise, and classify ambiguous cases as needs-human. (AC5)
func TestPreClaimIntakePrompt_AsksForFitForPurposeValidatedReplacement(t *testing.T) {
	root := newPreClaimIntakeHookTestRoot(t)
	store, b := newPreClaimIntakeHookTestStore(t, root)

	prompt, err := buildPreClaimIntakePrompt(root, store, b)
	require.NoError(t, err)

	lower := strings.ToLower(prompt)

	// Prompt must describe fit-for-purpose / prompt fitness as a rewrite goal.
	assert.True(t,
		strings.Contains(lower, "prompt fitness") || strings.Contains(lower, "fit-for-purpose"),
		"prompt must mention prompt fitness or fit-for-purpose; got:\n%s", prompt)

	// Prompt must allow replacement (not just appending).
	assert.True(t,
		strings.Contains(lower, "replacement") || strings.Contains(lower, "replace"),
		"prompt must allow replacement rewrites; got:\n%s", prompt)

	// Prompt must instruct the model to classify unclear cases as ambiguous_needs_human.
	assert.True(t,
		strings.Contains(lower, "ambiguous_needs_human") || strings.Contains(lower, "needs_human"),
		"prompt must instruct classification as ambiguous_needs_human for unclear cases; got:\n%s", prompt)
}
